from elasticsearch import Elasticsearch
from elasticsearch.helpers import bulk

class ElasticSearchApp:
    def __init__(self, host='localhost', port=9200):
        self.es = Elasticsearch([{'host': host, 'port': port}])

    def create_index(self, index_name, settings=None):
        if not self.es.indices.exists(index=index_name):
            self.es.indices.create(index=index_name, body=settings or {})
            
    def index_document(self, index_name, doc_type, document, doc_id=None):
        self.es.index(index=index_name, doc_type=doc_type, id=doc_id, body=document)
        
    def bulk_index_documents(self, index_name, doc_type, documents):
        bulk_requests = [
            {
                '_op_type': 'index',
                '_index': index_name,
                '_type': doc_type,
                '_id': doc.get('id'),
                '_source': doc
            }
            for doc in documents
        ]
        bulk(self.es, bulk_requests)
        
    def search_documents(self, index_name, query):
        return self.es.search(index=index_name, body={'query': {'match': {'content': query}}})

    def aggregate_logs(self, index_name, field):
        return self.es.search(index=index_name, body={
            'size': 0,
            'aggs': {
                'log_aggregation': {
                    'terms': {
                        'field': field,
                        'size': 10
                    }
                }
            }
        })

